import { useEffect, useState } from "react";
import api from "../api";

export default function Customers() {
    const [rows, setRows] = useState([]);
    const [loading, setLoading] = useState(true);
    const [form, setForm] = useState({ name: "", email: "", phone: "" });
    const [saving, setSaving] = useState(false);

    const load = async () => {
        setLoading(true);
        try {
            const { data } = await api.get("/api/customers");
            setRows(data || []);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => { load(); }, []);

    const save = async (e) => {
        e.preventDefault();
        setSaving(true);
        try {
            await api.post("/api/customers", form);
            setForm({ name: "", email: "", phone: "" });
            await load();
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Khách hàng</h2>
                    <p className="text-sm text-slate-500">Quản lý thông tin khách hàng</p>
                </div>
            </div>

            <form onSubmit={save} className="bg-white rounded-2xl border border-indigo-100 shadow p-4 grid grid-cols-1 md:grid-cols-4 gap-3">
                <input className="px-3 py-2 rounded-lg border" placeholder="Tên" value={form.name} onChange={e=>setForm(s=>({...s,name:e.target.value}))}/>
                <input className="px-3 py-2 rounded-lg border" placeholder="Email" value={form.email} onChange={e=>setForm(s=>({...s,email:e.target.value}))}/>
                <input className="px-3 py-2 rounded-lg border" placeholder="Điện thoại" value={form.phone} onChange={e=>setForm(s=>({...s,phone:e.target.value}))}/>
                <button disabled={saving} className="px-3 py-2 rounded-lg bg-indigo-600 text-white">{saving?"Đang lưu...":"Thêm"}</button>
            </form>

            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full">
                        <thead className="bg-indigo-50">
                        <tr className="text-left text-slate-600">
                            <th className="px-4 py-3">Tên</th>
                            <th className="px-4 py-3">Email</th>
                            <th className="px-4 py-3">Điện thoại</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {!loading && rows.map(c=>(
                            <tr key={c.id} className="hover:bg-indigo-50/40">
                                <td className="px-4 py-3 font-medium">{c.name}</td>
                                <td className="px-4 py-3">{c.email||"-"}</td>
                                <td className="px-4 py-3">{c.phone||"-"}</td>
                            </tr>
                        ))}
                        {loading && <tr><td className="px-4 py-3" colSpan={3}>Đang tải...</td></tr>}
                        {!loading && rows.length===0 && <tr><td className="px-4 py-3" colSpan={3}>Không có dữ liệu</td></tr>}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}
